var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으야아아앗!","JPN":"うぎゃあああっ！","ENG":"Gaaahhhh!","TWN":"呃啊啊啊！"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"으으, 침식체 놈들이 얼마나 헤집고 다닌 거죠? 도대체가 멀쩡한 도로가 없잖아요!","JPN":"うう、侵食体の奴ら、どれだけ暴れたの？　まともな道路がないわ！","ENG":"Ngh, how much have those C.O.s been destroying? All the roads are a mess!","TWN":"唉，那些侵蝕體把幾乎所有的道路都破壞掉了！"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"교통 통제 상황에 따르면 그 방향이 가장 안전한 최단루트야.","JPN":"交通統制状況によると、この方向が一番安全な最短ルートだよ。","ENG":"According to traffic control, this is the safest and shortest route.","TWN":"根據交通管制情況，那個方向是最安全、最短的路線。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"원래는 차원함선이 가장 빠른 수단이겠지만… 하늘에 깔린 침식체들의 공세를 견딜 만큼 튼튼한 함선은 지금 샤레이드에 없으니까.","JPN":"元々は次元艦船が一番早いけど……空いっぱいの侵食体たちの攻勢に耐えられるほど頑丈な艦船は今シャレードにないからね。","ENG":"A dimensional ship would be the fastest option, but... there are no dimensional ships in Charade that can withstand the attacks from all those C.O.s filling up the sky.","TWN":"本來乘坐次元艦船是最快的方法……但是目前查雷德沒有足夠堅固的艦船來抵禦空中的侵蝕體攻擊。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그런데 괜찮을까요? 방금 지나온 거리에도 침식체들이 저렇게 많은데 저희끼리 가버려도…","JPN":"でも、大丈夫でしょうか？　今通ってきた道にも侵食体があんなに沢山いるのに、私たちだけで行っちゃっても……","ENG":"Will it be okay, though? I just saw so many C.O.s on the street we just passed. If we ignore it...","TWN":"但這樣走掉真的可以嗎？我們在路上遇到了那麼多侵蝕體，如果連我們也離開……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"걱정 마. 내 직감에 의하면 우리가 가는 곳이 훨씬 더 위험할 걸?","JPN":"心配するな。私の直感によると、これから私たちが行くところはもっと危ないはずだから。","ENG":"Don't worry. My gut tells me that where we're headed is much more dangerous.","TWN":"別擔心。我的直覺告訴我，我們要去的地方比這裡更危險。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그리고, 사장님이 믿을만한 사람들에게 뒤를 맡겼다고 했으니 괜찮을 거야.","JPN":"それに、社長が信頼できる人たちに後ろを任せたって言ってたから、大丈夫だよ。","ENG":"And Boss said he left the city in good hands. So it should be fine.","TWN":"而且老闆說他會交給可以信任的人，所以不會有事的。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그럴까요…?","JPN":"そうでしょうか……？","ENG":"Really...?","TWN":"是這樣嗎……？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"물론. 다들 무사할 걸세.","JPN":"もちろんさ。みんな無事に決まってる。","ENG":"Of course. Everyone will be safe.","TWN":"當然，大家都沒事的。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"정 남아있는 사람들이 걱정된다면, 현장의 우리 특수요원과 통화라도 해보겠나?","JPN":"残っている人たちが心配なら、現場の特殊エージェントと通話してみるか？","ENG":"If you're that worried, would you like to call our special agents out on the field?","TWN":"如果你擔心其他人，可以聯絡一下現場的特務。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우와아, 특수요원이요?!","JPN":"うわあ、特殊エージェントですか！？","ENG":"Whoa, special agents?!","TWN":"哇，特務？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"여기는 블랙 버드. 샤레이드 방어 작전은 순조롭게 진행되고 있다. 무슨 일이지?","JPN":"こちら、ブラックバード。ブラックバード防御作戦は順調だ。どうした？","ENG":"This is Blackbird. The defense operation in Charade is going smooth. What's up?","TWN":"我是黑鳥。查雷德防禦戰進展順利，有什麼事嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"확인 차 연락했네. 우리 직원이 자네들의 안위를 걱정해서 말이야.","JPN":"確認がてら連絡した。私の職員が君たちの安否を心配していてね。","ENG":"Just checking up. My employee was worried about your safety.","TWN":"只是確認一下情況，我的員工很擔心你們的安全。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"붙들어 매라고. 코핀 컴퍼니. 블랙 버드의 파견대는 실패라는 걸 용납하지 않으니까.","JPN":"心配するな、コフィンカンパニー。ブラックバードの派遣隊は失敗を許さない。","ENG":"Leave it to us, Coffin Company. Blackbird's forces don't tolerate failure.","TWN":"不用擔心，科芬公司，因為黑鳥特遣隊絕不容忍失敗。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"오오오, 짱 멋진 코드네임! 멋진 선글라스랑 멋진 콧수염까지! 엄청 믿음직해 보여요!","JPN":"うわあ、カッコいいコードネーム！　素敵なサングラスに、立派な口ひげまで！　ものすごく頼もしいです！","ENG":"Ooooh, a super cool codename! Cool sunglasses and a cool mustache! He seems so reliable!","TWN":"哇喔喔喔！好帥的代號！還有墨鏡和鬍鬚！看起來超可靠的！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"훗, 펜릴 소대의 신참인가? 뭘 좀 아는 친구로군.","JPN":"ふっ、フェンリル小隊の新入りか？　わかっているな。","ENG":"Heh. A newbie in Fenrir Squad? You're pretty sharp.","TWN":"哈哈，芬里爾小隊的新人？你蠻有眼光的。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};